1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_PERCENT = 10;
3	const PERCENT_BASE = 100;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const INSURANCE_VALUE: Record<string, number> = {
15	  sword: 1000,
16	  amulet: 600,
17	  staff: 800,
18	  potion: 400,
19	  rune: 250,
20	  moonstone: 250,
21	};
22	
23	const DEDUCTIBLE = 100;
24	const CAP_MULTIPLIER = 2;
25	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
26	const HIGH_ENCHANTMENT_PAYOUT_RATIO = 0.5;
27	
28	interface Item {
29	  type: string;
30	  cursed?: boolean;
31	  enchantment?: number;
32	  material?: string;
33	}
34	
35	interface Damage {
36	  itemType: string;
37	  amount: number;
38	}
39	
40	interface Incident {
41	  cause?: string;
42	  damages: Damage[];
43	}
44	
45	interface Step {
46	  op: string;
47	  items?: Item[];
48	  policy?: number;
49	  incident?: Incident;
50	}
51	
52	interface Customer {
53	  yearsWithMHPCO: number;
54	}
55	
56	interface Scenario {
57	  customer: Customer;
58	  steps: Step[];
59	}
60	
61	const BLOCK_SIZE = 3;
62	const BLOCK_PREMIUM = 60;
63	const CURSE_SURCHARGE_PERCENT = 50;
64	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
65	const HIGH_ENCHANTMENT_THRESHOLD = 5;
66	const LOYALTY_DISCOUNT_PERCENT = 20;
67	const LOYALTY_THRESHOLD_YEARS = 2;
68	const FOLLOWUP_DISCOUNT_PERCENT = 15;
69	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
70	
71	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
72	
73	const percentOf = (amount: number, percent: number): number =>
74	  (amount * percent) / PERCENT_BASE;
75	
76	const percentIf = (condition: boolean, base: number, percent: number): number =>
77	  condition ? percentOf(base, percent) : 0;
78	
79	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type];
80	
81	const itemSurcharges = (item: Item): number => {
82	  const base = itemBasePremium(item);
83	  const curse = percentIf(item.cursed === true, base, CURSE_SURCHARGE_PERCENT);
84	  const highEnchantment = percentIf(
85	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
86	    base,
87	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
88	  );
89	  return curse + highEnchantment;
90	};
91	
92	const sumItemBases = (items: Item[]): number =>
93	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
94	
95	const sumSurcharges = (items: Item[]): number =>
96	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
97	
98	const partitionByType = (items: Item[]): Item[][] => {
99	  const groups: Record<string, Item[]> = {};
100	  items.forEach((item) => (groups[item.type] ??= []).push(item));
101	  return Object.values(groups);
102	};
103	
104	const isComponentBlock = (group: Item[]): boolean =>
105	  group.length === BLOCK_SIZE && isComponent(group[0]);
106	
107	const priceGroup = (group: Item[]): number =>
108	  isComponentBlock(group) ? BLOCK_PREMIUM : sumItemBases(group);
109	
110	const sumBasePremiums = (items: Item[]): number =>
111	  partitionByType(items).reduce((sum, group) => sum + priceGroup(group), 0);
112	
113	const isLoyalCustomer = (customer: Customer): boolean =>
114	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
115	
116	const applyPolicyModifiers = (
117	  base: number,
118	  customer: Customer,
119	  isFollowUp: boolean,
120	): number => {
121	  const firstInsurance = percentOf(base, FIRST_INSURANCE_PERCENT);
122	  const loyalty = percentIf(isLoyalCustomer(customer), base, LOYALTY_DISCOUNT_PERCENT);
123	  const followUp = percentIf(isFollowUp, base, FOLLOWUP_DISCOUNT_PERCENT);
124	  return base + firstInsurance - loyalty - followUp;
125	};
126	
127	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
128	  const policyBase = sumBasePremiums(items);
129	  const surcharges = sumSurcharges(items);
130	  return Math.ceil(applyPolicyModifiers(policyBase, customer, isFollowUp) + surcharges) + PROCESSING_FEE;
131	};
132	
133	const policyInsuranceSum = (items: Item[]): number =>
134	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
135	
136	const isHighEnchantmentClaim = (item: Item): boolean =>
137	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
138	
139	const reimbursableAmount = (damage: Damage, item: Item): number =>
140	  isHighEnchantmentClaim(item)
141	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATIO
142	    : damage.amount;
143	
144	const damagePayout = (damage: Damage, item: Item): number =>
145	  Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE);
146	
147	const findPolicyItem = (policyItems: Item[], itemType: string): Item =>
148	  policyItems.find((i) => i.type === itemType) as Item;
149	
150	const processClaim = (
151	  step: Step,
152	  policyItems: Item[],
153	): { payout: number; remainingCap: number } => {
154	  const damages = step.incident?.damages ?? [];
155	  const payout = damages.reduce(
156	    (sum, d) => sum + damagePayout(d, findPolicyItem(policyItems, d.itemType)),
157	    0,
158	  );
159	  const cap = policyInsuranceSum(policyItems) * CAP_MULTIPLIER;
160	  return { payout, remainingCap: cap - payout };
161	};
162	
163	const isQuote = (step: Step): boolean => step.op === "quote";
164	
165	const hasPriorQuote = (steps: Step[], index: number): boolean =>
166	  steps.slice(0, index).some(isQuote);
167	
168	const quoteStep = (
169	  step: Step,
170	  customer: Customer,
171	  isFollowUp: boolean,
172	): { premium: number } => ({
173	  premium: quotePremium(step.items ?? [], customer, isFollowUp),
174	});
175	
176	const claimStep = (
177	  step: Step,
178	  steps: Step[],
179	): { payout: number; remainingCap: number } =>
180	  processClaim(step, steps[step.policy ?? 0].items ?? []);
181	
182	const executeStep = (
183	  step: Step,
184	  customer: Customer,
185	  steps: Step[],
186	  index: number,
187	): { premium: number } | { payout: number; remainingCap: number } =>
188	  step.op === "claim"
189	    ? claimStep(step, steps)
190	    : quoteStep(step, customer, hasPriorQuote(steps, index));
191	
192	export const runScenario = (input: unknown): { results: unknown[] } => {
193	  const scenario = input as Scenario;
194	  return {
195	    results: scenario.steps.map((step, index) =>
196	      executeStep(step, scenario.customer, scenario.steps, index),
197	    ),
198	  };
199	};
